var (
	changedDurationRE    = regexp.MustCompile(`^\d+[hmsd]$`)
	changedDaysOrWeeksRE = regexp.MustCompile(`^\d+[wW]?$`)
	changedResourceTypes = []string{"transactions", "categories", "tags", "manual-accounts", "plaid-accounts", "recurring-items", "budgets"}
)

