func runChanged(ctx context.Context, args []string, since, types, dbPath string, limit int) ([]changedItem, error) {
	if len(args) > 0 {
		return nil, usageErr(fmt.Errorf("changed accepts no arguments"))
	}
	cutoff, err := parseChangedSince(since, time.Now)
	if err != nil {
		return nil, usageErr(err)
	}
	resourceTypes, err := parseChangedTypes(types)
	if err != nil {
		return nil, usageErr(err)
	}
	if limit < 0 {
		return nil, usageErr(fmt.Errorf("--limit must be zero or greater"))
	}
	db, err := openLocalStore(ctx, dbPath)
	if err != nil {
		return nil, err
	}
	defer db.Close()
	results := make([]changedItem, 0)
	for _, resourceType := range resourceTypes {
		if resourceType == "transactions" {
			items, err := queryChangedTransactions(ctx, db.DB(), cutoff, limit)
			if err != nil {
				return nil, err
			}
			results = append(results, capChangedItems(items, limit)...)
			continue
		}
		objs, err := loadResourceObjects(ctx, db, resourceType)
		if err != nil {
			return nil, err
		}
		results = append(results, capChangedItems(changedItemsFromObjects(resourceType, objs, cutoff), limit)...)
	}
	return results, nil
}

func parseChangedSince(raw string, now func() time.Time) (time.Time, error) {
	s := strings.TrimSpace(raw)
	if s == "" {
		return time.Time{}, fmt.Errorf("--since is required")
	}
	if changedDurationRE.MatchString(s) || changedDaysOrWeeksRE.MatchString(s) {
		d, err := changedDuration(s)
		if err != nil {
			return time.Time{}, err
		}
		return now().UTC().Add(-d), nil
	}
	t, err := time.Parse("2006-01-02", s)
	if err != nil {
		return time.Time{}, fmt.Errorf("--since must be a duration like 8h, 7d, 1w or a YYYY-MM-DD date")
	}
	return t.UTC(), nil
}

func changedDuration(s string) (time.Duration, error) {
	unit, text := s[len(s)-1], s
	if unit < '0' || unit > '9' {
		text = s[:len(s)-1]
	}
	count, err := strconv.Atoi(text)
	if err != nil {
		return 0, fmt.Errorf("invalid --since duration %q", s)
	}
	factor := 24 * time.Hour
	switch unit {
	case 'h':
		factor = time.Hour
	case 'm':
		factor = time.Minute
	case 's':
		factor = time.Second
	case 'w', 'W':
		factor = 7 * 24 * time.Hour
	}
	return time.Duration(count) * factor, nil
}

func parseChangedTypes(raw string) ([]string, error) {
	if strings.TrimSpace(raw) == "" {
		return append([]string(nil), changedResourceTypes...), nil
	}
	out, seen := make([]string, 0), map[string]bool{}
	for _, part := range strings.Split(raw, ",") {
		resourceType := strings.TrimSpace(part)
		if !slices.Contains(changedResourceTypes, resourceType) {
			return nil, fmt.Errorf("invalid --types value %q", resourceType)
		}
		if !seen[resourceType] {
			out, seen[resourceType] = append(out, resourceType), true
		}
	}
	return out, nil
}

func queryChangedTransactions(ctx context.Context, db *sql.DB, cutoff time.Time, limit int) ([]changedItem, error) {
	rows, err := db.QueryContext(ctx, `SELECT id, data FROM transactions WHERE updated_at >= ? ORDER BY updated_at DESC`, cutoff.UTC().Format(store.IndexedTimestampLayout))
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	out := make([]changedItem, 0)
	for rows.Next() {
		var rowID, raw string
		if err := rows.Scan(&rowID, &raw); err != nil {
			return nil, err
		}
		var obj map[string]any
		if json.Unmarshal([]byte(raw), &obj) != nil {
			continue
		}
		item, ok := changedItemFromObject("transactions", obj, cutoff)
		if !ok {
			continue
		}
		if item.ID == "" {
			item.ID = rowID
		}
		out = append(out, item)
		if limit > 0 && len(out) >= limit {
			break
		}
	}
	return out, rows.Err()
}
